create table rmais_suplier_site_guias (
    id_site       number generated by default on null as identity minvalue 1 maxvalue 9999999999999999999999999999 increment by 1 cache
    20 noorder nocycle nokeep noscale not null enable,
    descricao     varchar2(20 char) not null enable,
    situacao      varchar2(1 char) not null enable,
    supplier_site varchar2(20 byte)
);

alter table rmais_suplier_site_guias
    add constraint rmais_suplier_site_guias_pk primary key ( id_site )
        using index enable;


